// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if(isLoading){
		setTimeout(shoHideFields, 300);
		return;
	}

	setTimeout(shoHideFields, 300);

	function shoHideFields() {
		// hide tasker type on the simple vorm
		if (g_form.getControl('tasker_type')){
			g_form.setDisplay('tasker_type', false);
			g_form.setDisabled('tasker_type', true);	
		}
		g_form.setSectionDisplay('response_reviewerdecision', !g_form.isNewRecord());
	}
}
